using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // ── CalculateTotal: DataRow (uses double params, cast to decimal) ──────

    [TestMethod]
    [DataRow(10.00, 1, 0.0,  10.00,  DisplayName = "Single item, no tax")]
    [DataRow(10.00, 2, 0.0,  20.00,  DisplayName = "Two items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00,  DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62,  DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00,  5, 0.10, 0.00,   DisplayName = "Zero unit price")]
    [DataRow(99.99, 0, 0.15, 0.00,   DisplayName = "Zero quantity")]
    [DataRow(10.00, 1, 1.0,  20.00,  DisplayName = "100% tax rate")]
    public void CalculateTotal_WithDataRow_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal(
            (decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // ── CalculateTotal: DynamicData (native decimal precision) ─────────────

    public static IEnumerable<object[]> CalculateTotalCases
    {
        get
        {
            yield return [9.99m,  100, 0.07m,  1068.93m,  "Bulk order with 7% tax"];
            yield return [0.01m,  1,   0.0m,   0.01m,     "Minimum price, no tax"];
            yield return [1000m,  10,  0.25m,  12500.0m,  "High-value order, 25% tax"];
            yield return [49.95m, 4,   0.0625m, 212.2875m, "Precise fractional tax"];
        }
    }

    [TestMethod]
    [DynamicData(nameof(CalculateTotalCases))]
    public void CalculateTotal_WithDynamicData_ReturnsExpected(
        decimal unitPrice, int quantity, decimal taxRate,
        decimal expected, string scenario)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expected, result, $"Failed for: {scenario}");
    }

    // ── CalculateTotal: boundary / error cases ────────────────────────────

    [TestMethod]
    [DataRow(-1.0, 1, 0.1, DisplayName = "Negative unit price throws")]
    public void CalculateTotal_NegativeUnitPrice_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(
                (decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    public void CalculateTotal_NegativeQuantity_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, -1, 0.1m));
    }

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Tax rate below 0")]
    [DataRow(1.01,  DisplayName = "Tax rate above 1")]
    public void CalculateTotal_InvalidTaxRate_Throws(double taxRate)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, 1, (decimal)taxRate));
    }

    // ── ApplyDiscount: DataRow ────────────────────────────────────────────

    [TestMethod]
    [DataRow(100.00, 0.0,   100.00, DisplayName = "0% discount, full price")]
    [DataRow(100.00, 50.0,  50.00,  DisplayName = "50% discount")]
    [DataRow(100.00, 100.0, 0.00,   DisplayName = "100% discount, free")]
    [DataRow(79.99,  25.0,  59.9925, DisplayName = "25% off fractional price")]
    [DataRow(0.00,   50.0,  0.00,   DisplayName = "Zero price, any discount")]
    public void ApplyDiscount_WithDataRow_ReturnsExpected(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount(
            (decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // ── ApplyDiscount: DynamicData with method source ─────────────────────

    public static IEnumerable<object[]> GetDiscountEdgeCases()
    {
        yield return [249.99m, 10m,  224.991m, "10% loyalty discount"];
        yield return [1500m,   33.3m, 1000.5m, "Thirds discount"];
        yield return [0.01m,   99m,   0.0001m, "Near-total discount on penny"];
    }

    [TestMethod]
    [DynamicData(nameof(GetDiscountEdgeCases), DynamicDataSourceType.Method)]
    public void ApplyDiscount_WithDynamicDataMethod_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected, string scenario)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result, $"Failed for: {scenario}");
    }

    // ── ApplyDiscount: boundary / error cases ─────────────────────────────

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Discount below 0%")]
    [DataRow(100.01, DisplayName = "Discount above 100%")]
    public void ApplyDiscount_InvalidDiscountPercent_Throws(double discountPercent)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));
    }
}

